+	}
+	if spec.DetailWidth < minDetailWidth {
+		t.Errorf("detail width below min: %d", spec.DetailWidth)
+	}
+	if total > available {
+		t.Errorf("panel widths exceed available: %d > %d", total, available)
+	}
+}
